import{ControlFlow}from"../utils/util";class SizePanel{static Sizes={"800,600":{w:800,h:600},"1920,1080":{w:1920,h:1080},"2560,1440":{w:2560,h:1440},"3840,2160":{w:3840,h:2160},"2480,3508":{w:2480,h:3508},"3508,2480":{w:3508,h:2480},"2550,3300":{w:2550,h:3300},"1080,1080":{w:1080,h:1080}};#callback=()=>{};#elmP=null;constructor(elmP,callback){this.#elmP=elmP,this.#callback=callback,this.#init()}#init(){this.selSize=this.#elmP.querySelector("#sel-size"),this.customWidthEl=this.#elmP.querySelector("#cw"),this.customHeightEl=this.#elmP.querySelector("#ch"),this.#eventListener()}#eventListener(){this.selSize.addEventListener("change",(()=>{const{value:size}=this.selSize;if("custom"===size)this.customWidthEl.style.display=this.customHeightEl.style.display="inline-block";else{this.customWidthEl.style.display=this.customHeightEl.style.display="none";const[w,h]=size.split(",").map(Number);this.customWidthEl.value=w,this.customHeightEl.value=h,this.#callback({action:"setSize",size:size})}})),[this.customWidthEl,this.customHeightEl].forEach(((elm,idx,arr)=>{const handler=ControlFlow.debounce((e=>{this.#callback({action:"setSize",custom:{w:Number(arr[0].value),h:Number(arr[1].value)}})}),1e3);elm.addEventListener("input",handler)}))}}export{SizePanel};